65	data class BackupRestoreUiState(
66	    val backupArchives: List<BackupArchive> = emptyList(),
67	    val isLoading: Boolean = true,
68	    val isCreatingBackup: Boolean = false,
69	    val restoringArchiveId: String? = null,
70	    val lastRestoreRun: RestoreRun? = null,
71	    val successMessage: String? = null,
72	    val errorMessage: String? = null
73	)
74	
75	@HiltViewModel
76	class BackupRestoreViewModel @Inject constructor(
77	    private val backupRestoreUseCase: BackupRestoreUseCase
78	) : ViewModel() {
79	
80	    private val _uiState = MutableStateFlow(BackupRestoreUiState())
81	    val uiState: StateFlow<BackupRestoreUiState> = _uiState.asStateFlow()
82	
83	    init {
84	        loadBackups()
85	    }
86	
87	    fun loadBackups() {
88	        viewModelScope.launch {
89	            _uiState.update { it.copy(isLoading = true, errorMessage = null) }
90	            when (val archivesResult = backupRestoreUseCase.getAllBackups()) {
91	                is AppResult.Success -> {
92	                    _uiState.update { it.copy(isLoading = false, backupArchives = archivesResult.data) }
93	                }
94	                is AppResult.PermissionError -> {
95	                    _uiState.update { it.copy(isLoading = false, errorMessage = "Permission denied: ${archivesResult.code}") }
96	                }
97	                else -> {
98	                    _uiState.update { it.copy(isLoading = false, errorMessage = "Failed to load backups") }
99	                }
100	            }
101	        }
102	    }
103	
104	    fun exportBackupToStream(archiveId: String, outputStream: java.io.OutputStream) {
105	        viewModelScope.launch {
106	            _uiState.update { it.copy(errorMessage = null, successMessage = null) }
107	            when (val result = backupRestoreUseCase.exportBackupToStream(archiveId, outputStream)) {
108	                is AppResult.Success -> {
109	                    _uiState.update { it.copy(successMessage = "Backup exported successfully") }
110	                }
111	                else -> {
112	                    _uiState.update { it.copy(errorMessage = "Export failed") }
113	                }
114	            }
115	        }
116	    }
117	
118	    fun restoreFromStream(inputStream: java.io.InputStream) {
119	        viewModelScope.launch {
120	            _uiState.update { it.copy(restoringArchiveId = "imported", errorMessage = null, successMessage = null) }
121	            when (val result = backupRestoreUseCase.restoreFromStream(inputStream)) {
122	                is AppResult.Success -> {
123	                    _uiState.update {
124	                        it.copy(restoringArchiveId = null, lastRestoreRun = result.data,
125	                            successMessage = "Restore completed. Restart app to apply.")
126	                    }
127	                }
128	                is AppResult.ValidationError -> {
129	                    _uiState.update {
130	                        it.copy(restoringArchiveId = null,
131	                            errorMessage = result.globalErrors.firstOrNull() ?: "Validation error")
132	                    }
133	                }
134	                else -> {
135	                    _uiState.update { it.copy(restoringArchiveId = null, errorMessage = "Restore failed") }
136	                }
137	            }
138	        }
139	    }
140	
141	    fun createBackup() {
142	        viewModelScope.launch {
143	            _uiState.update { it.copy(isCreatingBackup = true, errorMessage = null, successMessage = null) }
144	            when (val result = backupRestoreUseCase.createBackup()) {
145	                is AppResult.Success -> {
146	                    val archivesResult = backupRestoreUseCase.getAllBackups()
147	                    val archives = (archivesResult as? AppResult.Success)?.data ?: emptyList()
148	                    _uiState.update {
149	                        it.copy(
150	                            isCreatingBackup = false,
151	                            backupArchives = archives,
152	                            successMessage = "Backup created successfully"
153	                        )
154	                    }
155	                }
156	                is AppResult.PermissionError -> {
157	                    _uiState.update {
158	                        it.copy(isCreatingBackup = false, errorMessage = "Permission denied")
159	                    }
160	                }
161	                is AppResult.ValidationError -> {
162	                    _uiState.update {
163	                        it.copy(
164	                            isCreatingBackup = false,
165	                            errorMessage = result.globalErrors.firstOrNull()
166	                                ?: result.fieldErrors.values.firstOrNull()
167	                                ?: "Validation error"
168	                        )
169	                    }
170	                }
171	                is AppResult.ConflictError -> {
172	                    _uiState.update {
173	                        it.copy(isCreatingBackup = false, errorMessage = result.message)
174	                    }
175	                }
176	                is AppResult.NotFoundError -> {
177	                    _uiState.update {
178	                        it.copy(isCreatingBackup = false, errorMessage = "Resource not found")
179	                    }
180	                }
181	                is AppResult.SystemError -> {
182	                    _uiState.update {
183	                        it.copy(isCreatingBackup = false, errorMessage = result.message)
184	                    }
185	                }
186	            }
187	        }
188	    }
189	
190	    fun restoreBackup(archiveId: String) {
191	        viewModelScope.launch {
192	            _uiState.update { it.copy(restoringArchiveId = archiveId, errorMessage = null, successMessage = null) }
193	            when (val result = backupRestoreUseCase.restoreFromBackup(archiveId)) {
194	                is AppResult.Success -> {
195	                    _uiState.update {
196	                        it.copy(
197	                            restoringArchiveId = null,
198	                            lastRestoreRun = result.data,
199	                            successMessage = "Restore completed successfully"
200	                        )
201	                    }
202	                }
203	                is AppResult.PermissionError -> {
204	                    _uiState.update {
205	                        it.copy(restoringArchiveId = null, errorMessage = "Permission denied")
206	                    }
207	                }
208	                is AppResult.ValidationError -> {
209	                    _uiState.update {
210	                        it.copy(
211	                            restoringArchiveId = null,
212	                            errorMessage = result.globalErrors.firstOrNull()
213	                                ?: result.fieldErrors.values.firstOrNull()
214	                                ?: "Validation error"
215	                        )
216	                    }
217	                }
218	                is AppResult.ConflictError -> {
219	                    _uiState.update {
220	                        it.copy(restoringArchiveId = null, errorMessage = result.message)
221	                    }
222	                }
223	                is AppResult.NotFoundError -> {
224	                    _uiState.update {
225	                        it.copy(restoringArchiveId = null, errorMessage = "Archive not found")
226	                    }
227	                }
228	                is AppResult.SystemError -> {
229	                    _uiState.update {
230	                        it.copy(restoringArchiveId = null, errorMessage = result.message)
231	                    }
232	                }
233	            }
234	        }
235	    }
236	
237	    fun clearError() {
238	        _uiState.update { it.copy(errorMessage = null) }
239	    }
240	
241	    fun clearSuccess() {
242	        _uiState.update { it.copy(successMessage = null) }
243	    }
244	}
