249	
250	private val backupDateFormatter: DateTimeFormatter =
251	    DateTimeFormatter.ofPattern("MMM dd, yyyy HH:mm")
252	        .withZone(ZoneId.systemDefault())
253	
254	@OptIn(ExperimentalMaterial3Api::class)
255	@Composable
256	fun BackupRestoreScreen(
257	    onNavigateBack: () -> Unit,
258	    viewModel: BackupRestoreViewModel = hiltViewModel()
259	) {
260	    val state by viewModel.uiState.collectAsState()
261	    val snackbarHostState = remember { SnackbarHostState() }
262	
263	    LaunchedEffect(state.errorMessage) {
264	        state.errorMessage?.let { message ->
265	            snackbarHostState.showSnackbar(message)
266	            viewModel.clearError()
267	        }
268	    }
269	
270	    LaunchedEffect(state.successMessage) {
271	        state.successMessage?.let { message ->
272	            snackbarHostState.showSnackbar(message)
273	            viewModel.clearSuccess()
274	        }
275	    }
276	
277	    Scaffold(
278	        topBar = {
279	            TopAppBar(
280	                title = { Text("Backup & Restore") },
281	                navigationIcon = {
282	                    IconButton(onClick = onNavigateBack) {
283	                        Icon(Icons.AutoMirrored.Filled.ArrowBack, contentDescription = "Back")
284	                    }
285	                },
286	                colors = TopAppBarDefaults.topAppBarColors(
287	                    containerColor = MaterialTheme.colorScheme.primary,
288	                    titleContentColor = MaterialTheme.colorScheme.onPrimary,
289	                    navigationIconContentColor = MaterialTheme.colorScheme.onPrimary
290	                )
291	            )
292	        },
293	        snackbarHost = { SnackbarHost(snackbarHostState) }
294	    ) { padding ->
295	        Column(
296	            modifier = Modifier
297	                .fillMaxSize()
298	                .padding(padding)
299	                .padding(16.dp)
300	        ) {
301	            // Create Backup button
302	            Button(
303	                onClick = viewModel::createBackup,
304	                modifier = Modifier.fillMaxWidth(),
305	                enabled = !state.isCreatingBackup
306	            ) {
307	                if (state.isCreatingBackup) {
308	                    CircularProgressIndicator(
309	                        color = MaterialTheme.colorScheme.onPrimary
310	                    )
311	                } else {
312	                    Text("Create Backup")
313	                }
314	            }
315	
316	            Spacer(modifier = Modifier.height(16.dp))
317	
318	            // Last restore info
319	            if (state.lastRestoreRun != null) {
320	                val restore = state.lastRestoreRun!!
321	                Card(
322	                    modifier = Modifier.fillMaxWidth(),
323	                    elevation = CardDefaults.cardElevation(defaultElevation = 2.dp),
324	                    colors = CardDefaults.cardColors(
325	                        containerColor = MaterialTheme.colorScheme.tertiaryContainer
326	                    )
327	                ) {
328	                    Column(
329	                        modifier = Modifier
330	                            .fillMaxWidth()
331	                            .padding(16.dp)
332	                    ) {
333	                        Text(
334	                            text = "Last Restore",
335	                            style = MaterialTheme.typography.titleSmall,
336	                            fontWeight = FontWeight.Bold
337	                        )
338	                        Spacer(modifier = Modifier.height(4.dp))
339	                        Text(
340	                            text = "Status: ${restore.status}",
341	                            style = MaterialTheme.typography.bodySmall
342	                        )
343	                        Text(
344	                            text = "Started: ${backupDateFormatter.format(restore.startedAt)}",
345	                            style = MaterialTheme.typography.bodySmall
346	                        )
347	                        if (restore.completedAt != null) {
348	                            Text(
349	                                text = "Completed: ${backupDateFormatter.format(restore.completedAt)}",
350	                                style = MaterialTheme.typography.bodySmall
351	                            )
352	                        }
353	                        if (restore.errorMessage != null) {
354	                            Text(
355	                                text = "Error: ${restore.errorMessage}",
356	                                style = MaterialTheme.typography.bodySmall,
357	                                color = MaterialTheme.colorScheme.error
358	                            )
359	                        }
360	                    }
361	                }
362	                Spacer(modifier = Modifier.height(16.dp))
363	            }
364	
365	            // Backup list header
366	            Text(
367	                text = "Backup Archives",
368	                style = MaterialTheme.typography.titleMedium,
369	                fontWeight = FontWeight.Bold
370	            )
371	
372	            Spacer(modifier = Modifier.height(8.dp))
373	
374	            if (state.isLoading) {
375	                Box(
376	                    modifier = Modifier.fillMaxSize(),
377	                    contentAlignment = Alignment.Center
378	                ) {
379	                    CircularProgressIndicator()
380	                }
381	            } else if (state.backupArchives.isEmpty()) {
382	                Box(
383	                    modifier = Modifier.fillMaxSize(),
384	                    contentAlignment = Alignment.Center
385	                ) {
386	                    Text(
387	                        text = "No backup archives found",
388	                        style = MaterialTheme.typography.bodyLarge,
389	                        color = MaterialTheme.colorScheme.onSurfaceVariant
390	                    )
391	                }
392	            } else {
393	                LazyColumn(
394	                    verticalArrangement = Arrangement.spacedBy(8.dp)
395	                ) {
396	                    items(state.backupArchives, key = { it.id }) { archive ->
397	                        BackupArchiveDetailCard(
398	                            archive = archive,
399	                            isRestoring = state.restoringArchiveId == archive.id,
400	                            onRestore = { viewModel.restoreBackup(archive.id) }
401	                        )
402	                    }
403	                    item { Spacer(modifier = Modifier.height(16.dp)) }
404	                }
405	            }
406	        }
407	    }
408	}
409	
410	@Composable
411	private fun BackupArchiveDetailCard(
412	    archive: BackupArchive,
413	    isRestoring: Boolean,
414	    onRestore: () -> Unit
415	) {
416	    Card(
417	        modifier = Modifier.fillMaxWidth(),
418	        elevation = CardDefaults.cardElevation(defaultElevation = 2.dp)
419	    ) {
420	        Column(
421	            modifier = Modifier
422	                .fillMaxWidth()
423	                .padding(16.dp)
424	        ) {
425	            Row(
426	                modifier = Modifier.fillMaxWidth(),
427	                horizontalArrangement = Arrangement.SpaceBetween,
428	                verticalAlignment = Alignment.CenterVertically
429	            ) {
430	                Text(
431	                    text = "Backup ${archive.id.take(8)}",
432	                    style = MaterialTheme.typography.titleSmall,
433	                    fontWeight = FontWeight.Bold,
434	                    modifier = Modifier.weight(1f)
435	                )
436	                Spacer(modifier = Modifier.width(8.dp))
437	                BackupArchiveStatusChip(status = archive.status)
438	            }
439	
440	            Spacer(modifier = Modifier.height(8.dp))
441	
442	            BackupInfoRow(label = "App Version", value = archive.appVersion)
443	            BackupInfoRow(label = "Schema Version", value = archive.schemaVersion.toString())
444	            BackupInfoRow(label = "Encryption", value = archive.encryptionMethod)
445	            BackupInfoRow(label = "Created", value = backupDateFormatter.format(archive.createdAt))
446	            BackupInfoRow(label = "Created By", value = archive.createdBy)
447	
448	            if (archive.filePath != null) {
449	                BackupInfoRow(label = "File", value = archive.filePath)
450	            }
451	
452	            if (archive.fileSizeBytes != null && archive.fileSizeBytes > 0) {
453	                BackupInfoRow(label = "Size", value = "${archive.fileSizeBytes} bytes")
454	            }
455	
456	            if (archive.status == BackupStatus.SUCCEEDED || archive.status == BackupStatus.VERIFIED) {
457	                Spacer(modifier = Modifier.height(12.dp))
458	                Divider()
459	                Spacer(modifier = Modifier.height(12.dp))
460	                OutlinedButton(
461	                    onClick = onRestore,
462	                    modifier = Modifier.fillMaxWidth(),
463	                    enabled = !isRestoring
464	                ) {
465	                    if (isRestoring) {
466	                        CircularProgressIndicator(
467	                            modifier = Modifier.padding(end = 8.dp)
468	                        )
469	                    }
470	                    Text("Restore from this Backup")
471	                }
472	            }
473	        }
474	    }
475	}
476	
477	@Composable
478	private fun BackupInfoRow(label: String, value: String) {
479	    Row(
480	        modifier = Modifier
481	            .fillMaxWidth()
482	            .padding(vertical = 2.dp),
483	        horizontalArrangement = Arrangement.SpaceBetween,
484	        verticalAlignment = Alignment.CenterVertically
485	    ) {
486	        Text(
487	            text = label,
488	            style = MaterialTheme.typography.bodySmall,
489	            color = MaterialTheme.colorScheme.onSurfaceVariant
490	        )
491	        Text(
492	            text = value,
493	            style = MaterialTheme.typography.bodySmall,
494	            fontWeight = FontWeight.Medium
495	        )
496	    }
497	}
498	
499	@Composable
500	private fun BackupArchiveStatusChip(status: BackupStatus) {
501	    val (label, containerColor, contentColor) = when (status) {
502	        BackupStatus.REQUESTED -> Triple(
503	            "Requested",
504	            MaterialTheme.colorScheme.surfaceVariant,
505	            MaterialTheme.colorScheme.onSurfaceVariant
506	        )
507	        BackupStatus.RUNNING -> Triple(
508	            "Running",
509	            MaterialTheme.colorScheme.primaryContainer,
510	            MaterialTheme.colorScheme.onPrimaryContainer
511	        )
512	        BackupStatus.SUCCEEDED -> Triple(
513	            "Succeeded",
514	            MaterialTheme.colorScheme.tertiary,
515	            MaterialTheme.colorScheme.onTertiary
516	        )
517	        BackupStatus.FAILED -> Triple(
518	            "Failed",
519	            MaterialTheme.colorScheme.error,
520	            MaterialTheme.colorScheme.onError
521	        )
522	        BackupStatus.RETRYABLE -> Triple(
523	            "Retryable",
524	            MaterialTheme.colorScheme.tertiaryContainer,
525	            MaterialTheme.colorScheme.onTertiaryContainer
526	        )
527	        BackupStatus.VERIFIED -> Triple(
528	            "Verified",
529	            MaterialTheme.colorScheme.tertiary,
530	            MaterialTheme.colorScheme.onTertiary
531	        )
532	    }
533	    Surface(
534	        shape = MaterialTheme.shapes.small,
535	        color = containerColor,
536	        contentColor = contentColor
537	    ) {
538	        Text(
539	            text = label,
540	            modifier = Modifier.padding(horizontal = 12.dp, vertical = 4.dp),
541	            style = MaterialTheme.typography.labelSmall
542	        )
543	    }
544	}
