3	import com.learnmart.app.domain.model.*
4	import com.learnmart.app.domain.repository.OperationsRepository
5	import com.learnmart.app.domain.usecase.auth.CheckPermissionUseCase
6	import com.learnmart.app.util.AppResult
7	import javax.inject.Inject
8	
9	/**
10	 * Permission-gated access to operations data.
11	 * All operations screen data must flow through this use case, not directly from repositories.
12	 */
13	class ManageOperationsUseCase @Inject constructor(
14	    private val operationsRepository: OperationsRepository,
15	    private val checkPermission: CheckPermissionUseCase
16	) {
17	    suspend fun getImportJobs(): AppResult<List<ImportJob>> {
18	        if (!checkPermission.hasAnyPermission(Permission.IMPORT_MANAGE, Permission.AUDIT_VIEW)) {
19	            return AppResult.PermissionError("Requires import.manage or audit.view")
20	        }
21	        return AppResult.Success(operationsRepository.getAllImportJobs())
22	    }
23	
24	    suspend fun getDiscrepancyCases(limit: Int = 50, offset: Int = 0): AppResult<List<DiscrepancyCase>> {
25	        if (!checkPermission.hasAnyPermission(Permission.PAYMENT_RECONCILE, Permission.AUDIT_VIEW)) {
26	            return AppResult.PermissionError("Requires payment.reconcile or audit.view")
27	        }
28	        return AppResult.Success(operationsRepository.getAllDiscrepancyCases(limit, offset))
29	    }
30	
31	    suspend fun getBackupArchives(): AppResult<List<BackupArchive>> {
32	        if (!checkPermission.hasPermission(Permission.BACKUP_RUN)) {
33	            return AppResult.PermissionError("Requires backup.run")
34	        }
35	        return AppResult.Success(operationsRepository.getAllBackupArchives())
36	    }
37	
38	    suspend fun getExportJobs(limit: Int = 50, offset: Int = 0): AppResult<List<ExportJob>> {
39	        if (!checkPermission.hasAnyPermission(Permission.EXPORT_MANAGE, Permission.AUDIT_VIEW)) {
40	            return AppResult.PermissionError("Requires export.manage or audit.view")
41	        }
42	        return AppResult.Success(operationsRepository.getAllExportJobs(limit, offset))
43	    }
44	}
