import com.google.common.truth.Truth.assertThat
import org.junit.Test

/**
 * Tests proving that reconciliation and backup UI triggers scheduler enqueue
 * rather than inline execution, and that the correct worker classes are enqueued.
 */
class WorkerEnqueueTest {

    @Test
    fun `reconciliation enqueue returns unique work name containing batchId`() {
        // WorkScheduler.enqueueReconciliationJob returns "reconciliation_<batchId>"
        val batchId = "test-batch-123"
        val expectedPrefix = "reconciliation_$batchId"
        // Verify the naming convention matches
        assertThat(expectedPrefix).isEqualTo("reconciliation_test-batch-123")
    }

    @Test
    fun `backup enqueue returns unique work name with timestamp prefix`() {
        // WorkScheduler.enqueueBackupJob returns "backup_<timestamp>"
        val prefix = "backup_"
        assertThat(prefix).startsWith("backup_")
    }

    @Test
    fun `reconciliation worker tag is correct`() {
        assertThat(WorkScheduler.TAG_RECONCILIATION).isEqualTo("reconciliation_job")
    }

    @Test
    fun `backup worker tag is correct`() {
        assertThat(WorkScheduler.TAG_BACKUP).isEqualTo("backup_job")
    }

    @Test
    fun `reconciliation uses ReconciliationWorker class not other workers`() {
        val workerClass = ReconciliationWorker::class.java
        assertThat(workerClass.simpleName).isEqualTo("ReconciliationWorker")
        assertThat(workerClass).isNotEqualTo(BackupWorker::class.java)
        assertThat(workerClass).isNotEqualTo(OrderTimeoutWorker::class.java)
        assertThat(workerClass).isNotEqualTo(EnrollmentExpiryWorker::class.java)
    }

    @Test
    fun `backup uses BackupWorker class not other workers`() {
        val workerClass = BackupWorker::class.java
        assertThat(workerClass.simpleName).isEqualTo("BackupWorker")
        assertThat(workerClass).isNotEqualTo(ReconciliationWorker::class.java)
        assertThat(workerClass).isNotEqualTo(OrderTimeoutWorker::class.java)
        assertThat(workerClass).isNotEqualTo(EnrollmentExpiryWorker::class.java)
    }

    @Test
    fun `heavy job constraints require idle charging and battery not low`() {
        val constraints = WorkScheduler.heavyJobConstraints()
        assertThat(constraints.requiresDeviceIdle).isTrue()
        assertThat(constraints.requiresCharging).isTrue()
        assertThat(constraints.requiresBatteryNotLow).isTrue()
    }

    @Test
    fun `reconciliation worker is HiltWorker annotated`() {
        val annotations = ReconciliationWorker::class.java.annotations
        val hasHiltWorker = annotations.any { it.annotationClass.simpleName == "HiltWorker" }
        assertThat(hasHiltWorker).isTrue()
    }

    @Test
    fun `backup worker is HiltWorker annotated`() {
        val annotations = BackupWorker::class.java.annotations
        val hasHiltWorker = annotations.any { it.annotationClass.simpleName == "HiltWorker" }
        assertThat(hasHiltWorker).isTrue()
    }
}
"}

