import com.learnmart.app.domain.model.DefaultRolePermissions
import com.learnmart.app.domain.model.Permission
import com.learnmart.app.domain.model.RoleType
import com.google.common.truth.Truth.assertThat
import org.junit.Test

/**
 * Tests proving that operations route access is correctly gated by role permissions.
 * These validate the permission model that the OperationsRouteGuard relies on.
 */
class OperationsRouteGuardTest {

    private val operationsPermissions = setOf(
        Permission.IMPORT_MANAGE, Permission.EXPORT_MANAGE,
        Permission.PAYMENT_RECONCILE, Permission.BACKUP_RUN, Permission.AUDIT_VIEW
    )

    @Test
    fun `administrator has all operations permissions`() {
        val adminPerms = DefaultRolePermissions.permissionsForRole(RoleType.ADMINISTRATOR)
        for (perm in operationsPermissions) {
            assertThat(adminPerms).contains(perm)
        }
    }

    @Test
    fun `finance clerk has import export and reconcile permissions`() {
        val financePerms = DefaultRolePermissions.permissionsForRole(RoleType.FINANCE_CLERK)
        assertThat(financePerms).contains(Permission.IMPORT_MANAGE)
        assertThat(financePerms).contains(Permission.EXPORT_MANAGE)
        assertThat(financePerms).contains(Permission.PAYMENT_RECONCILE)
    }

    @Test
    fun `learner has no operations permissions`() {
        val learnerPerms = DefaultRolePermissions.permissionsForRole(RoleType.LEARNER)
        for (perm in operationsPermissions) {
            assertThat(learnerPerms).doesNotContain(perm)
        }
    }

    @Test
    fun `instructor has no operations permissions`() {
        val instructorPerms = DefaultRolePermissions.permissionsForRole(RoleType.INSTRUCTOR)
        for (perm in operationsPermissions) {
            assertThat(instructorPerms).doesNotContain(perm)
        }
    }

    @Test
    fun `teaching assistant has no operations permissions`() {
        val taPerms = DefaultRolePermissions.permissionsForRole(RoleType.TEACHING_ASSISTANT)
        for (perm in operationsPermissions) {
            assertThat(taPerms).doesNotContain(perm)
        }
    }

    @Test
    fun `registrar has audit_view but not import or backup`() {
        val registrarPerms = DefaultRolePermissions.permissionsForRole(RoleType.REGISTRAR)
        assertThat(registrarPerms).contains(Permission.AUDIT_VIEW)
        assertThat(registrarPerms).doesNotContain(Permission.IMPORT_MANAGE)
        assertThat(registrarPerms).doesNotContain(Permission.BACKUP_RUN)
        assertThat(registrarPerms).doesNotContain(Permission.EXPORT_MANAGE)
    }

    @Test
    fun `backup route requires BACKUP_RUN permission`() {
        val backupPerms = arrayOf(Permission.BACKUP_RUN, Permission.RESTORE_RUN)
        // Admin has both
        val adminPerms = DefaultRolePermissions.permissionsForRole(RoleType.ADMINISTRATOR)
        assertThat(backupPerms.any { it in adminPerms }).isTrue()
        // Learner has neither
        val learnerPerms = DefaultRolePermissions.permissionsForRole(RoleType.LEARNER)
        assertThat(backupPerms.any { it in learnerPerms }).isFalse()
    }

    @Test
    fun `reconciliation route requires PAYMENT_RECONCILE permission`() {
        val adminPerms = DefaultRolePermissions.permissionsForRole(RoleType.ADMINISTRATOR)
        assertThat(adminPerms).contains(Permission.PAYMENT_RECONCILE)
        val financePerms = DefaultRolePermissions.permissionsForRole(RoleType.FINANCE_CLERK)
        assertThat(financePerms).contains(Permission.PAYMENT_RECONCILE)
        val learnerPerms = DefaultRolePermissions.permissionsForRole(RoleType.LEARNER)
        assertThat(learnerPerms).doesNotContain(Permission.PAYMENT_RECONCILE)
    }

    @Test
    fun `import route requires IMPORT_MANAGE permission`() {
        val financePerms = DefaultRolePermissions.permissionsForRole(RoleType.FINANCE_CLERK)
        assertThat(financePerms).contains(Permission.IMPORT_MANAGE)
        val learnerPerms = DefaultRolePermissions.permissionsForRole(RoleType.LEARNER)
        assertThat(learnerPerms).doesNotContain(Permission.IMPORT_MANAGE)
    }

    @Test
    fun `dashboard shows operations only for admin and finance clerk`() {
        // Verify the dashboard visibility logic matches RoleType checks
        val visibleRoles = listOf(RoleType.ADMINISTRATOR, RoleType.FINANCE_CLERK)
        val hiddenRoles = listOf(RoleType.LEARNER, RoleType.INSTRUCTOR, RoleType.TEACHING_ASSISTANT)

        for (role in visibleRoles) {
            val perms = DefaultRolePermissions.permissionsForRole(role)
            val hasAnyOpsPermission = operationsPermissions.any { it in perms }
            assertThat(hasAnyOpsPermission).isTrue()
        }

        for (role in hiddenRoles) {
            val perms = DefaultRolePermissions.permissionsForRole(role)
            // These roles should not have import/export/backup/reconcile
            assertThat(perms).doesNotContain(Permission.IMPORT_MANAGE)
            assertThat(perms).doesNotContain(Permission.BACKUP_RUN)
            assertThat(perms).doesNotContain(Permission.PAYMENT_RECONCILE)
        }
    }
}
"}

