{"file_path": "C:\Users\amana\OneDrive\Desktop\Files\Eaglepoint\April 10\Task-143\repo\app\src\test\java\com\learnmart\app\domain\usecase\operations\ReconciliationWorkerAtomicityTest.kt", "content": "package com.learnmart.app.domain.usecase.operations

import com.learnmart.app.data.local.LearnMartRoomDatabase
import com.learnmart.app.domain.model.*
import com.learnmart.app.domain.repository.AuditRepository
import com.learnmart.app.domain.repository.OperationsRepository
import com.learnmart.app.domain.repository.PaymentRepository
import com.learnmart.app.domain.usecase.auth.CheckPermissionUseCase
import com.learnmart.app.security.SessionManager
import com.learnmart.app.util.AppResult
import com.google.common.truth.Truth.assertThat
import io.mockk.*
import kotlinx.coroutines.test.runTest
import org.junit.Before
import org.junit.Test
import java.math.BigDecimal
import java.time.Instant

/**
 * Tests proving that the reconciliation path (both use-case and worker-level)
 * is atomic: mid-flow failure does not leave partial persisted state,
 * and success persists all expected outputs.
 */
class ReconciliationWorkerAtomicityTest {
    private lateinit var operationsRepository: OperationsRepository
    private lateinit var paymentRepository: PaymentRepository
    private lateinit var auditRepository: AuditRepository
    private lateinit var checkPermission: CheckPermissionUseCase
    private lateinit var sessionManager: SessionManager
    private lateinit var database: LearnMartRoomDatabase
    private lateinit var useCase: ReconciliationUseCase

    @Before
    fun setUp() {
        operationsRepository = mockk(relaxed = true)
        paymentRepository = mockk(relaxed = true)
        auditRepository = mockk(relaxed = true)
        checkPermission = mockk()
        sessionManager = mockk()
        database = mockk(relaxed = true)
        every { sessionManager.getCurrentUserId() } returns "finance-1"
        every { sessionManager.getCurrentSessionId() } returns "session-1"
        coEvery { checkPermission.hasPermission(Permission.PAYMENT_RECONCILE) } returns true
        coEvery { database.withTransaction(any<suspend () -> Unit>()) } coAnswers {
            val block = firstArg<suspend () -> Unit>()
            block()
        }
        useCase = ReconciliationUseCase(
            operationsRepository, paymentRepository, auditRepository,
            checkPermission, sessionManager, database
        )
    }

    @Test
    fun `successful reconciliation persists run matches and discrepancies in transaction`() = runTest {
        coEvery { operationsRepository.getSettlementBatchById("batch-1") } returns SettlementImportBatch(
            "batch-1", "job-1", "BATCH-001", true, 2, Instant.now()
        )
        val row1 = SettlementImportRow(
            "row-1", "batch-1", "ext-1", "pay-1", BigDecimal("100.00"),
            "CASH", "CLEARED", Instant.now(), "{}", true, null, false
        )
        val row2 = SettlementImportRow(
            "row-2", "batch-1", "ext-2", null, BigDecimal("50.00"),
            "CHECK", "CLEARED", Instant.now(), "{}", true, null, false
        )
        coEvery { operationsRepository.getSettlementRowsByBatch("batch-1") } returns listOf(row1, row2)
        coEvery { paymentRepository.getPaymentById("pay-1") } returns PaymentRecord(
            "pay-1", "order-1", BigDecimal("100.00"), TenderType.CASH, PaymentStatus.ALLOCATED,
            null, "clerk", Instant.now(), null, Instant.now(), 1
        )
        coEvery { paymentRepository.getPaymentsForOrder("pay-1") } returns emptyList()
        coEvery { operationsRepository.getImportJobById("job-1") } returns ImportJob(
            "job-1", "file.csv", "csv", 100L, ImportJobStatus.READY_TO_APPLY,
            2, 2, 0, null, "finance-1", Instant.now(), Instant.now()
        )

        val result = useCase.runReconciliation("batch-1")
        assertThat(result).isInstanceOf(AppResult.Success::class.java)

        // Verify transaction was used
        coVerify(exactly = 1) { database.withTransaction(any<suspend () -> Unit>()) }
        // Verify reconciliation run created
        coVerify { operationsRepository.createReconciliationRun(any()) }
        // Verify matches created
        coVerify { operationsRepository.createReconciliationMatches(any()) }
        // Verify discrepancy created (for row2 with no reference)
        coVerify { operationsRepository.createDiscrepancyCase(any()) }
        // Verify import job updated
        coVerify { operationsRepository.updateImportJob(match { it.status == ImportJobStatus.APPLIED }) }
        // Verify audit event
        coVerify { auditRepository.logEvent(match { it.actionType == AuditActionType.RECONCILIATION_RUN }) }
    }

    @Test
    fun `transaction failure rolls back all writes`() = runTest {
        coEvery { operationsRepository.getSettlementBatchById("batch-1") } returns SettlementImportBatch(
            "batch-1", "job-1", "BATCH-001", true, 1, Instant.now()
        )
        val row = SettlementImportRow(
            "row-1", "batch-1", "ext-1", "pay-1", BigDecimal("100.00"),
            "CASH", "CLEARED", Instant.now(), "{}", true, null, false
        )
        coEvery { operationsRepository.getSettlementRowsByBatch("batch-1") } returns listOf(row)
        coEvery { paymentRepository.getPaymentById("pay-1") } returns null
