import com.learnmart.app.domain.usecase.auth.CheckPermissionUseCase
import com.learnmart.app.security.SessionManager
import com.learnmart.app.util.AppResult
import com.google.common.truth.Truth.assertThat
import io.mockk.*
import kotlinx.coroutines.test.runTest
import org.junit.Before
import org.junit.Test

/**
 * Tests proving:
 * - Backup archive creation uses correct validation and audit logging
 * - Permission gating works correctly
 * - Blank passphrase fails closed
 * - Export emits correct audit action type
 * - Error states are distinct
 */
class BackupWorkManagerIntegrationTest {
    private lateinit var operationsRepository: OperationsRepository
    private lateinit var policyRepository: PolicyRepository
    private lateinit var auditRepository: AuditRepository
    private lateinit var checkPermission: CheckPermissionUseCase
    private lateinit var sessionManager: SessionManager

    @Before
    fun setUp() {
        operationsRepository = mockk(relaxed = true)
        policyRepository = mockk(relaxed = true)
        auditRepository = mockk(relaxed = true)
        checkPermission = mockk()
        sessionManager = mockk()
        every { sessionManager.getCurrentUserId() } returns "admin-1"
        every { sessionManager.getCurrentSessionId() } returns "session-1"
    }

    @Test
    fun `backup requires BACKUP_RUN permission`() = runTest {
        coEvery { checkPermission.hasPermission(Permission.BACKUP_RUN) } returns false
        val useCase = createBackupUseCase()
        val result = useCase.getAllBackups()
        assertThat(result).isInstanceOf(AppResult.PermissionError::class.java)
    }

    @Test
    fun `blank passphrase fails closed for backup creation`() = runTest {
        coEvery { checkPermission.hasPermission(Permission.BACKUP_RUN) } returns true
        coEvery { policyRepository.getPolicyValue(PolicyType.BACKUP, "backup_passphrase", "") } returns ""
        val useCase = createBackupUseCase()
        val result = useCase.createBackup()
        assertThat(result).isInstanceOf(AppResult.ValidationError::class.java)
        val error = result as AppResult.ValidationError
        assertThat(error.globalErrors.first()).contains("passphrase")
    }

    @Test
    fun `export uses EXPORT_COMPLETED audit action type`() = runTest {
        coEvery { checkPermission.hasPermission(Permission.EXPORT_MANAGE) } returns true
        val exportUseCase = ExportUseCase(operationsRepository, auditRepository, checkPermission, sessionManager)
        val result = exportUseCase.createExport("orders", "csv", "data", 10)
        assertThat(result).isInstanceOf(AppResult.Success::class.java)

        val eventSlot = slot<AuditEvent>()
        coVerify { auditRepository.logEvent(capture(eventSlot)) }
        assertThat(eventSlot.captured.actionType).isEqualTo(AuditActionType.EXPORT_COMPLETED)
        assertThat(eventSlot.captured.actionType).isNotEqualTo(AuditActionType.IMPORT_COMPLETED)
        assertThat(eventSlot.captured.actionType).isNotEqualTo(AuditActionType.IMPORT_STARTED)
    }

    @Test
    fun `backup archive status transitions are enforced`() {
        assertThat(BackupStatus.REQUESTED.canTransitionTo(BackupStatus.RUNNING)).isTrue()
        assertThat(BackupStatus.RUNNING.canTransitionTo(BackupStatus.SUCCEEDED)).isTrue()
        assertThat(BackupStatus.RUNNING.canTransitionTo(BackupStatus.FAILED)).isTrue()
        assertThat(BackupStatus.SUCCEEDED.canTransitionTo(BackupStatus.VERIFIED)).isTrue()
        assertThat(BackupStatus.VERIFIED.canTransitionTo(BackupStatus.RUNNING)).isFalse()
        assertThat(BackupStatus.SUCCEEDED.canTransitionTo(BackupStatus.RUNNING)).isFalse()
    }

    @Test
    fun `restore requires RESTORE_RUN permission`() = runTest {
        coEvery { checkPermission.hasPermission(Permission.RESTORE_RUN) } returns false
        val useCase = createBackupUseCase()
        val result = useCase.restoreFromBackup("archive-1")
        assertThat(result).isInstanceOf(AppResult.PermissionError::class.java)
    }

    @Test
    fun `restore fails for non-existent archive`() = runTest {
        coEvery { checkPermission.hasPermission(Permission.RESTORE_RUN) } returns true
        coEvery { operationsRepository.getBackupArchiveById("missing") } returns null
        val useCase = createBackupUseCase()
        val result = useCase.restoreFromBackup("missing")
        assertThat(result).isInstanceOf(AppResult.NotFoundError::class.java)
    }

    @Test
    fun `getAllBackups success returns list`() = runTest {
        coEvery { checkPermission.hasPermission(Permission.BACKUP_RUN) } returns true
        coEvery { operationsRepository.getAllBackupArchives() } returns emptyList()
        val useCase = createBackupUseCase()
        val result = useCase.getAllBackups()
        assertThat(result).isInstanceOf(AppResult.Success::class.java)
        assertThat((result as AppResult.Success).data).isEmpty()
    }

    private fun createBackupUseCase(): BackupRestoreUseCase {
        // Can't fully construct without Context, but for permission/validation tests
        // we use mockk to verify the paths that don't need real file I/O
        return BackupRestoreUseCase(
            context = mockk(relaxed = true),
            operationsRepository = operationsRepository,
            policyRepository = policyRepository,
            auditRepository = auditRepository,
            checkPermission = checkPermission,
            sessionManager = sessionManager
        )
    }
}
"}

