import com.learnmart.app.domain.model.RoleType
import com.google.common.truth.Truth.assertThat
import org.junit.Test

/**
 * Tests proving the dashboard operations entry visibility by role.
 * The dashboard shows the Operations card only when the user has
 * ADMINISTRATOR or FINANCE_CLERK role.
 */
class DashboardOperationsVisibilityTest {

    /**
     * Mirrors the visibility logic in DashboardScreen.NavigationCardsSection:
     * `if (isAdministrator || isFinanceClerk) { show Operations card }`
     */
    private fun isOperationsVisible(roles: List<RoleType>): Boolean {
        val isAdministrator = roles.contains(RoleType.ADMINISTRATOR)
        val isFinanceClerk = roles.contains(RoleType.FINANCE_CLERK)
        return isAdministrator || isFinanceClerk
    }

    @Test
    fun `operations visible for administrator`() {
        assertThat(isOperationsVisible(listOf(RoleType.ADMINISTRATOR))).isTrue()
    }

    @Test
    fun `operations visible for finance clerk`() {
        assertThat(isOperationsVisible(listOf(RoleType.FINANCE_CLERK))).isTrue()
    }

    @Test
    fun `operations visible for admin plus other roles`() {
        assertThat(isOperationsVisible(listOf(RoleType.ADMINISTRATOR, RoleType.INSTRUCTOR))).isTrue()
    }

    @Test
    fun `operations hidden for learner`() {
        assertThat(isOperationsVisible(listOf(RoleType.LEARNER))).isFalse()
    }

    @Test
    fun `operations hidden for instructor`() {
        assertThat(isOperationsVisible(listOf(RoleType.INSTRUCTOR))).isFalse()
    }

    @Test
    fun `operations hidden for teaching assistant`() {
        assertThat(isOperationsVisible(listOf(RoleType.TEACHING_ASSISTANT))).isFalse()
    }

    @Test
    fun `operations hidden for registrar`() {
        assertThat(isOperationsVisible(listOf(RoleType.REGISTRAR))).isFalse()
    }

    @Test
    fun `operations hidden for empty roles`() {
        assertThat(isOperationsVisible(emptyList())).isFalse()
    }

    @Test
    fun `operations visible when user has both learner and admin roles`() {
        assertThat(isOperationsVisible(listOf(RoleType.LEARNER, RoleType.ADMINISTRATOR))).isTrue()
    }

    @Test
    fun `operations visible when user has both registrar and finance clerk roles`() {
        assertThat(isOperationsVisible(listOf(RoleType.REGISTRAR, RoleType.FINANCE_CLERK))).isTrue()
    }
}
"}

